# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']
profiles = db['user_profiles']

# Create user profile
@app.route('/profile', methods=['POST'])
def create_profile():
    data = request.json
    profile_id = profiles.insert_one(data).inserted_id
    return jsonify({'message': 'Profile created successfully', 'id': str(profile_id)}), 201

# Get user profile by ID
@app.route('/profile/<profile_id>', methods=['GET'])
def get_profile(profile_id):
    profile = profiles.find_one({'_id': profile_id})
    if profile:
        return jsonify(profile)
    else:
        return jsonify({'message': 'Profile not found'}), 404

# Query user profiles
@app.route('/profiles', methods=['GET'])
def query_profiles():
    query = request.args.to_dict()
    result = list(profiles.find(query))
    return jsonify(result)

# Aggregation pipeline example
@app.route('/profile/stats', methods=['GET'])
def profile_stats():
    pipeline = [
        {"$group": {"_id": "$age", "count": {"$sum": 1}}}
    ]
    stats = list(profiles.aggregate(pipeline))
    return jsonify(stats)

if __name__ == '__main__':
    app.run(debug=True)